### Swift If-Else

The `if-else` statement executes code based on a boolean condition. Swift's `if` statements are flexible and can include optional binding, multiple conditions, and `where` clauses.

**Basic If-Else:**

```swift
let age = 18

if age >= 18 {
    print("You can vote")
} else {
    print("Too young to vote")
}

// Multiple else if branches
let score = 75

if score >= 90 {
    print("A")
} else if score >= 80 {
    print("B")
} else if score >= 70 {
    print("C")
} else if score >= 60 {
    print("D")
} else {
    print("F")
}
```

**If with Optional Binding:**

```swift
let username: String? = "Alice"

if let name = username {
    print("Welcome, \(name)!")
} else {
    print("Please log in")
}

// Multiple binding with condition
if let first = optionalA, let second = optionalB, first < second {
    print("\(first) is less than \(second)")
}
```

**If as an Expression:**

Since Swift 5.9, `if` can be used as an expression:

```swift
let greeting = if isMorning { "Good morning" } else { "Hello" }
```

> **Key Point:** The `if` expression syntax requires all branches to return the same type.

```swift
let temperature = 25
let weatherDescription = if temperature > 20 {
    "warm"
} else {
    "cool"
}
```

codeExample:
import Foundation

// Basic if-else
let hour = 14

var timeOfDay: String
if hour < 12 {
    timeOfDay = "morning"
} else if hour < 17 {
    timeOfDay = "afternoon"
} else {
    timeOfDay = "evening"
}
print("Good \(timeOfDay)!")

// If as expression (Swift 5.9+)
let isWeekend = false
let activity = if isWeekend { "relax" } else { "work" }
print("Time to \(activity)")

// Optional binding in if
let name: String? = "John"
let greeting: String
if let name = name {
    greeting = "Hello, \(name)"
} else {
    greeting = "Hello, stranger"
}
print(greeting)
